#include <stdio.h>
#include <pthread.h>

void* thread_function(void* arg) {
    int thread_num = *(int*)arg;
    printf("Thread %d is running\n", thread_num);
    printf("Thread %d: Thread ID = %lu\n", thread_num, (unsigned long)pthread_self());
    return NULL;
}

int main() {
    pthread_t threads[3];
    int thread_args[3];
    int i, result;

    for (i = 0; i < 3; i++) {
        thread_args[i] = i + 1;
        result = pthread_create(&threads[i], NULL, thread_function, &thread_args[i]);
        if (result != 0) {
            perror("Thread creation failed");
            return 1;
        }
    }

    // Wait for all threads to complete
    for (i = 0; i < 3; i++) {
        pthread_join(threads[i], NULL);
    }

    printf("All threads completed\n");
    return 0;
}

// COMPILE: gcc -pthread program.c -o program
// RUN: ./program

#include <stdio.h>
#include <pthread.h>

#define NUM_THREADS 5
#define INCREMENTS 1000

int shared_counter = 0;
pthread_mutex_t counter_mutex = PTHREAD_MUTEX_INITIALIZER;

void* increment_counter(void* arg) {
    int thread_id = *(int*)arg;

    for (int i = 0; i < INCREMENTS; i++) {
        pthread_mutex_lock(&counter_mutex);
        // Critical section - only one thread can modify shared_counter
        shared_counter++;
        pthread_mutex_unlock(&counter_mutex);
    }

    printf("Thread %d finished. Counter = %d\n", thread_id, shared_counter);
    return NULL;
}

int main() {
    pthread_t threads[NUM_THREADS];
    int thread_ids[NUM_THREADS];

    for (int i = 0; i < NUM_THREADS; i++) {
        thread_ids[i] = i;
        pthread_create(&threads[i], NULL, increment_counter, &thread_ids[i]);
    }

    for (int i = 0; i < NUM_THREADS; i++) {
        pthread_join(threads[i], NULL);
    }

    printf("Final counter value: %d (expected: %d)\n", 
           shared_counter, NUM_THREADS * INCREMENTS);
    pthread_mutex_destroy(&counter_mutex);
    return 0;
}

// Method 1: Extending Thread class
class MyThread extends Thread {
    private int threadId;

    public MyThread(int id) {
        this.threadId = id;
    }

    @Override
    public void run() {
        System.out.println("Thread " + threadId + " starting");
        System.out.println("Thread ID: " + this.getId());
        System.out.println("Thread " + threadId + " finished");
    }
}

// Method 2: Implementing Runnable interface
class MyRunnable implements Runnable {
    private int taskId;

    public MyRunnable(int id) {
        this.taskId = id;
    }

    @Override
    public void run() {
        System.out.println("Runnable Task " + taskId + " executing");
    }
}

public class ThreadDemo {
    public static void main(String[] args) {
        // Creating thread using Thread class
        MyThread thread1 = new MyThread(1);
        thread1.start();

        // Creating thread using Runnable interface
        MyRunnable runnable = new MyRunnable(1);
        Thread thread2 = new Thread(runnable);
        thread2.start();

        // Using lambda expression (Java 8+)
        Thread thread3 = new Thread(() -> {
            System.out.println("Lambda thread executing");
        });
        thread3.start();

        // Wait for threads to complete
        try {
            thread1.join();
            thread2.join();
            thread3.join();
        } catch (InterruptedException e) {
            e.printStackTrace();
        }

        System.out.println("All threads completed");
    }
}
